import{_ as i,C as o,o as a,c as l,a2 as r,b,w as e,a as n,E as s,a3 as m}from"./chunks/framework.Crpw6aS5.js";const A=JSON.parse('{"title":"RabbitMQ 消息队列","description":"","frontmatter":{"title":"RabbitMQ 消息队列","module":"mq-rabbitmq","difficulty":"intermediate","interviewFrequency":"high","tags":["RabbitMQ","消息队列","AMQP","面试高频"],"codeExample":"04-middleware/mq-rabbitmq-examples/src/main/java/com/example/mq/rabbitmq/","relatedEntries":["/4-middleware/4.2-mq-kafka/","/2-framework/2.2-springboot/"],"prerequisites":["/2-framework/2.2-springboot/","/1-java-core/1.3-concurrent/"],"estimatedTime":"30min"},"headers":[],"relativePath":"4-middleware/4.1-mq-rabbitmq/00-index.md","filePath":"4-middleware/4.1-mq-rabbitmq/00-index.md","lastUpdated":null}'),h={name:"4-middleware/4.1-mq-rabbitmq/00-index.md"};function f(c,t,E,p,g,q){const d=o("Mermaid");return a(),l("div",null,[t[1]||(t[1]=r('<h1 id="rabbitmq-消息队列" tabindex="-1">RabbitMQ 消息队列 <a class="header-anchor" href="#rabbitmq-消息队列" aria-label="Permalink to &quot;RabbitMQ 消息队列&quot;">​</a></h1><h2 id="概念说明" tabindex="-1">概念说明 <a class="header-anchor" href="#概念说明" aria-label="Permalink to &quot;概念说明&quot;">​</a></h2><p>RabbitMQ 是基于 <strong>AMQP（Advanced Message Queuing Protocol）</strong> 协议实现的开源消息中间件，由 Erlang 语言编写，具有高可靠性、灵活路由、集群扩展等特点。它是 Java 后端面试中<strong>消息队列方向的高频考察模块</strong>，从 Exchange 路由机制到消息可靠性保证，再到死信队列和延迟消息，都是面试常见考点。</p><p>本模块从 RabbitMQ 的核心概念出发，深入讲解消息可靠性、高级特性以及 Spring Boot 集成，帮助你系统掌握 RabbitMQ 在面试和工作中的关键技术。</p><blockquote><p>⚠️ 需要 RabbitMQ 环境的示例，请先启动 Docker：<code>docker compose -f docker/docker-compose.mq.yml up -d</code></p></blockquote><h2 id="知识点列表" tabindex="-1">知识点列表 <a class="header-anchor" href="#知识点列表" aria-label="Permalink to &quot;知识点列表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>序号</th><th>知识点</th><th>难度</th><th>面试频率</th><th>文档链接</th></tr></thead><tbody><tr><td>1</td><td>RabbitMQ 核心概念</td><td>⭐⭐</td><td>🔥🔥🔥</td><td><a href="./01-rabbitmq.html">rabbitmq</a></td></tr><tr><td>2</td><td>消息可靠性</td><td>⭐⭐⭐</td><td>🔥🔥🔥</td><td><a href="./02-rabbitmq-reliability.html">rabbitmq-reliability</a></td></tr><tr><td>3</td><td>高级特性</td><td>⭐⭐⭐</td><td>🔥🔥🔥</td><td><a href="./03-rabbitmq-advanced.html">rabbitmq-advanced</a></td></tr><tr><td>4</td><td>Spring Boot 集成</td><td>⭐⭐</td><td>🔥🔥</td><td><a href="./04-rabbitmq-spring.html">rabbitmq-spring</a></td></tr><tr><td>5</td><td>RabbitMQ 面试指南</td><td>⭐⭐⭐</td><td>🔥🔥🔥</td><td><a href="./99-interview.html">interview</a></td></tr></tbody></table><h2 id="推荐学习顺序" tabindex="-1">推荐学习顺序 <a class="header-anchor" href="#推荐学习顺序" aria-label="Permalink to &quot;推荐学习顺序&quot;">​</a></h2>',8)),(a(),b(m,null,{default:e(()=>[s(d,{id:"mermaid-131",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20A%5B%221.%20%E6%A0%B8%E5%BF%83%E6%A6%82%E5%BF%B5%3Cbr%2F%3EExchange%2FQueue%2FBinding%22%5D%20--%3E%20B%5B%222.%20%E6%B6%88%E6%81%AF%E5%8F%AF%E9%9D%A0%E6%80%A7%3Cbr%2F%3EConfirm%2FACK%2F%E6%8C%81%E4%B9%85%E5%8C%96%22%5D%0A%20%20%20%20B%20--%3E%20C%5B%223.%20%E9%AB%98%E7%BA%A7%E7%89%B9%E6%80%A7%3Cbr%2F%3E%E6%AD%BB%E4%BF%A1%E9%98%9F%E5%88%97%2F%E5%BB%B6%E8%BF%9F%E6%B6%88%E6%81%AF%22%5D%0A%20%20%20%20A%20--%3E%20D%5B%224.%20Spring%20Boot%20%E9%9B%86%E6%88%90%3Cbr%2F%3ERabbitTemplate%2F%40RabbitListener%22%5D%0A%20%20%20%20B%20--%3E%20D%0A%20%20%20%20C%20--%3E%20E%5B%225.%20%E9%9D%A2%E8%AF%95%E6%8C%87%E5%8D%97%E6%B1%87%E6%80%BB%22%5D%0A%20%20%20%20D%20--%3E%20E%0A%0A%20%20%20%20style%20A%20fill%3A%23e1f5fe%0A%20%20%20%20style%20B%20fill%3A%23e1f5fe%0A%20%20%20%20style%20C%20fill%3A%23fff3e0%0A%20%20%20%20style%20D%20fill%3A%23f3e5f5%0A%20%20%20%20style%20E%20fill%3A%23e8f5e9%0A"})]),fallback:e(()=>[...t[0]||(t[0]=[n(" Loading... ",-1)])]),_:1})),t[2]||(t[2]=r('<p><strong>学习路线说明</strong>：</p><ul><li>🔵 <strong>核心原理层</strong>（1-2）：Exchange 路由机制和消息可靠性是 RabbitMQ 的基石</li><li>🟠 <strong>高级特性层</strong>（3）：死信队列和延迟消息是面试高频实战场景</li><li>🟣 <strong>集成应用层</strong>（4）：Spring Boot 集成是工作中的日常使用</li><li>🟢 <strong>面试汇总</strong>（5）：高频面试题和追问链路</li></ul><h2 id="rabbitmq-vs-kafka-对比" tabindex="-1">RabbitMQ vs Kafka 对比 <a class="header-anchor" href="#rabbitmq-vs-kafka-对比" aria-label="Permalink to &quot;RabbitMQ vs Kafka 对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>RabbitMQ</th><th>Kafka</th></tr></thead><tbody><tr><td>消息模型</td><td>队列模型（点对点 + 发布订阅）</td><td>发布订阅模型（基于 Topic + Partition）</td></tr><tr><td>吞吐量</td><td>万级 QPS</td><td>百万级 QPS</td></tr><tr><td>延迟</td><td>微秒级</td><td>毫秒级</td></tr><tr><td>消息顺序</td><td>单队列有序</td><td>单分区有序</td></tr><tr><td>消息回溯</td><td>不支持（消费即删除）</td><td>支持（基于 Offset 回溯）</td></tr><tr><td>协议</td><td>AMQP</td><td>自定义协议</td></tr><tr><td>适用场景</td><td>业务解耦、异步通知、延迟任务</td><td>日志收集、流处理、大数据管道</td></tr><tr><td>运维复杂度</td><td>较低</td><td>较高（依赖 ZooKeeper/KRaft）</td></tr></tbody></table><p><strong>选型建议</strong>：</p><ul><li>业务消息（订单、通知、异步任务）→ <strong>RabbitMQ</strong></li><li>日志收集、数据管道、流处理 → <strong>Kafka</strong></li><li>对延迟敏感的场景 → <strong>RabbitMQ</strong></li><li>对吞吐量要求极高的场景 → <strong>Kafka</strong></li></ul><h2 id="相关模块链接" tabindex="-1">相关模块链接 <a class="header-anchor" href="#相关模块链接" aria-label="Permalink to &quot;相关模块链接&quot;">​</a></h2><ul><li><a href="/4-middleware/4.2-mq-kafka/">Kafka 消息队列</a> — 另一种主流消息中间件</li><li><a href="/2-framework/2.2-springboot/">Spring Boot</a> — RabbitMQ 与 Spring Boot 集成</li><li><a href="/5-distributed/5.1-distributed/">分布式系统</a> — 消息最终一致性方案</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://www.rabbitmq.com/docs" target="_blank" rel="noreferrer">RabbitMQ 官方文档</a></li><li><a href="https://book.douban.com/subject/27591386/" target="_blank" rel="noreferrer">《RabbitMQ 实战指南》— 朱忠华</a></li><li><a href="https://www.rabbitmq.com/tutorials/amqp-concepts" target="_blank" rel="noreferrer">AMQP 0-9-1 协议规范</a></li></ul>',10))])}const B=i(h,[["render",f]]);export{A as __pageData,B as default};
